insert x xs =
  if length xs == 0 then [x]
  else if x <= head xs then cons x xs
  else cons (head xs) (insert x (tail xs))

isort xs =
  if length xs == 0 then []
  else insert (head xs) (isort (tail xs))

main =
  let _ = print (show (head (isort [9,3,7,1,5])))
  0

main =
  let _ = print (join "" (reverse (chars "abcde")))
  0

flatten xss =
  if length xss == 0 then []
  else append (head xss) (flatten (tail xss))

main =
  let _ = print (show (head (flatten [[10],[20,30],[40]])))
  0

